insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('21284', 'e.kor', 'ekor', '', '', '["Nomina","Nomina","Nomina","Nomina","Nomina","Nomina","kiasan"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"bagian tubuh binatang dan sebagainya yang paling belakang, baik berupa sambungan dari tulang punggung maupun sebagai lekatan","contoh":[]},{"nomor":"2","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"kata penggolong untuk binatang","contoh":[{"nomor":2,"teks":"dua -- harimau"}]},{"nomor":"3","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"sesuatu yang rupanya (keadaannya) seperti ekor","contoh":[{"nomor":2,"teks":"-- layang-layang"}]},{"nomor":"4","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"bagian yang di belakang sekali (tentang pesawat, pasukan, dan sebagainya)","contoh":[{"nomor":2,"teks":"-- pasukan itu baru saja lewat di sini"}]},{"nomor":"5","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"akibat dari kejadian atau keadaan sebelumnya","contoh":[{"nomor":2,"teks":"perkara itu merupakan -- dari peristiwa semalam"}]},{"nomor":"6","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"},{"kode":"ki","nama":"kiasan","tipe":"kelas_kata"}],"definisi":"orang yang harus ditanggung (diurus, dibiayai, dan sebagainya); tanggungan","contoh":[{"nomor":2,"teks":"dia harus bekerja keras karena --nya banyak"}]}]', null, '["berekor","berekor-ekor","mengekor","pengekor","seekor"]', '["ekor anjing","ekor barisan","ekor belangkas","ekor berita","ekor cambuk","ekor gemuk","ekor hangus","ekor kemacetan","ekor kok","ekor komet","ekor kucing","ekor kuda","ekor kuning","ekor kuning pisang","ekor lagu","ekor lipas","ekor magnet","ekor naga","ekor panah","ekor pegas","ekor pesawat","ekor pipi","ekor pulau","ekor tikus","ekor tupai"]', '["anjing ditepuk, menjungkit ekor","anjing menyalak di ekor (pantat) gajah","anjing menyalak di ekor gajah","asal selamat ke seberang, biar bergantung di ekor (buaya)","bagai belut digetil ekor","bagai langau di ekor gajah","bagai pinang tua merah ekor","berkelahi di ekor alahan","habis minyak sepasu, ekor anjing takkan lurus","hendak meluruskan ekor anjing","jauh menyalak kuat, dekat mencawat ekor","mati puyuh hendakkan ekor","muka licin, ekor berkedal","mulut bagai ekor ayam diembus","muncung seperti ekor ayam","sembunyi tuma (kepala tersuruk), ekor kelihatan","sembunyi tuma (kepala tersuruk, ekor kelihatan)","sepuluh kapal datang, anjing pun bercawat ekor","seperti anjing bercawat ekor","seperti anjing terpanggang ekor","seperti ular mengutik-ngutik ekor"]', '["efek ekor jas"]', '[{"peribahasa":"anjing ditepuk, menjungkit ekor","makna":"Peribahasa ini menggambarkan seseorang yang mudah terpengaruh oleh sanjungan atau pujian, sehingga menjadi sombong atau angkuh."},{"peribahasa":"anjing menyalak di ekor (pantat) gajah","makna":"Peribahasa ini menggambarkan seseorang yang berani melawan atau mengkritik pihak yang lebih kuat atau berkuasa, namun melakukannya dari jarak yang aman atau tanpa risiko."},{"peribahasa":"anjing menyalak di ekor gajah","makna":"Sama seperti sebelumnya, peribahasa ini menggambarkan seseorang yang berani melawan atau mengkritik pihak yang lebih kuat atau berkuasa, namun melakukannya dari jarak yang aman atau tanpa risiko."},{"peribahasa":"asal selamat ke seberang, biar bergantung di ekor (buaya)","makna":"Peribahasa ini menggambarkan seseorang yang rela melakukan apa saja, bahkan hal yang berbahaya atau memalukan sekalipun, demi mencapai tujuannya atau menyelamatkan diri dari kesulitan."},{"peribahasa":"bagai belut digetil ekor","makna":"Peribahasa ini menggambarkan seseorang yang sangat lincah, cerdik, dan sulit ditangkap atau dikalahkan."},{"peribahasa":"bagai langau di ekor gajah","makna":"Peribahasa ini menggambarkan seseorang yang selalu mengikuti atau bergantung pada orang yang lebih berkuasa atau berpengaruh, dengan harapan mendapatkan keuntungan atau perlindungan."},{"peribahasa":"bagai pinang tua merah ekor","makna":"Peribahasa ini menggambarkan seseorang yang sudah tua namun masih berjiwa muda, bersemangat, dan menarik."},{"peribahasa":"berkelahi di ekor alahan","makna":"Peribahasa ini menggambarkan perselisihan atau perdebatan yang tidak penting atau tidak pada tempatnya."},{"peribahasa":"habis minyak sepasu, ekor anjing takkan lurus","makna":"Peribahasa ini menggambarkan sifat atau watak seseorang yang sulit diubah, meskipun telah diberi banyak nasihat atau dididik dengan berbagai cara."},{"peribahasa":"hendak meluruskan ekor anjing","makna":"Peribahasa ini menggambarkan usaha yang sia-sia atau tidak mungkin berhasil, karena mencoba mengubah sesuatu yang sudah menjadi kodratnya."},{"peribahasa":"jauh menyalak kuat, dekat mencawat ekor","makna":"Peribahasa ini menggambarkan seseorang yang hanya berani berbicara atau mengancam dari jauh, namun menjadi penakut ketika berhadapan langsung."},{"peribahasa":"mati puyuh hendakkan ekor","makna":"Peribahasa ini menggambarkan seseorang yang rela berkorban atau menanggung risiko besar demi sesuatu yang tidak seberapa nilainya."},{"peribahasa":"muka licin, ekor berkedal","makna":"Peribahasa ini menggambarkan seseorang yang penampilan luarnya tampak baik, sopan, dan jujur, namun sebenarnya memiliki sifat yang buruk, licik, atau jahat."},{"peribahasa":"mulut bagai ekor ayam diembus","makna":"Peribahasa ini menggambarkan seseorang yang tidak bisa menyimpan rahasia atau selalu membicarakan hal-hal yang tidak penting."},{"peribahasa":"muncung seperti ekor ayam","makna":"Peribahasa ini menggambarkan seseorang yang suka mencampuri urusan orang lain atau banyak bicara."},{"peribahasa":"sembunyi tuma (kepala tersuruk), ekor kelihatan","makna":"Peribahasa ini menggambarkan perbuatan menyembunyikan kejahatan atau kesalahan yang tidak sempurna, sehingga akhirnya terbongkar juga."},{"peribahasa":"sembunyi tuma (kepala tersuruk, ekor kelihatan)","makna":"Sama seperti sebelumnya, peribahasa ini menggambarkan perbuatan menyembunyikan kejahatan atau kesalahan yang tidak sempurna, sehingga akhirnya terbongkar juga."},{"peribahasa":"sepuluh kapal datang, anjing pun bercawat ekor","makna":"Peribahasa ini menggambarkan suasana yang sangat ramai dan sibuk, sehingga semua orang turut serta dalam kesibukan tersebut."},{"peribahasa":"seperti anjing bercawat ekor","makna":"Peribahasa ini menggambarkan seseorang yang sangat ketakutan atau pengecut."},{"peribahasa":"seperti anjing terpanggang ekor","makna":"Peribahasa ini menggambarkan seseorang yang sangat gelisah, resah, dan tidak bisa diam karena suatu masalah atau kesulitan."},{"peribahasa":"seperti ular mengutik-ngutik ekor","makna":"Peribahasa ini menggambarkan seseorang yang sedang dalam kesulitan atau bahaya, namun masih berusaha untuk melawan atau membela diri."}]');
