insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('21596', 'elang tikus', 'elang tikus', '', 'elang', '[]', '[{"nomor":"1","kelasKata":[],"definisi":"burung pemangsa yang berukuran sedang, berbulu putih, abu-abu, dan hitam, terdapat bercak hitam pada bahu dan bulu utama, memakan tikus, kelelawar, burung kecil, reptil, dan serangga, berhabitat di lahan terbuka, dan tersebar di Sumatra, Kalimantan, Jawa, Sulawesi, Nusa Tenggara, dan Papua〔Elanus caeruleus〕","contoh":[]}]', null, '[]', '[]', '[]', '[]', '[]');
insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('122346', 'e.lang', 'elang', '', '', '["Nomina","Sunda"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"},{"kode":"Sd","nama":"Sunda","tipe":"bahasa"}],"definisi":"sebutan untuk anak lelaki sultan Cirebon","contoh":[]}]', null, '[]', '["elang alap","elang alap Halmahera","elang alap Maluku","elang alap shikra","elang bangkai","elang belalang","elang bondol","elang emas","elang flores","elang gunung","elang harpa","elang harpy papua","elang hitam","elang jambul","elang jawa","elang kelelawar","elang laut","elang laut putih","elang malam","elang merah","elang paria","elang rawa tutul","elang sikap","elang tikus","elang tiram","elang ular bido"]', '["ayam ditambat, disambar elang","belalang disangka elang","belalang hendak menjadi elang","dahulu elang pulau, kini telah menjadi burung pungguk","rezeki elang tak akan dapat (dimakan) oleh musang (burung pipit)","sepantun elang dengan ayam, lambat laun akan disambar jua","sepantun elang dengan ayam, lambat laun disambar juga","seperti elang menyongsong angin"]', '[]', '[{"peribahasa":"ayam ditambat, disambar elang","makna":"Peribahasa ini menggambarkan nasib yang malang atau kemalangan yang datang berturut-turut. Meskipun sudah dalam keadaan terikat atau terbatas, seseorang masih bisa tertimpa musibah yang lebih besar, diibaratkan seperti ayam yang sudah ditambat namun masih disambar oleh elang."},{"peribahasa":"belalang disangka elang","makna":"Ungkapan ini merujuk pada kesalahan dalam menilai atau mempersepsikan sesuatu. Sering kali, seseorang atau suatu hal yang dianggap remeh atau tidak berbahaya (belalang) ternyata memiliki kekuatan atau potensi yang jauh lebih besar dari yang dibayangkan (elang)."},{"peribahasa":"belalang hendak menjadi elang","makna":"Peribahasa ini digunakan untuk menyindir seseorang yang memiliki ambisi atau cita-cita yang tidak sepadan dengan kemampuannya. Orang tersebut ingin meniru atau menyamai kedudukan orang yang lebih tinggi, padahal ia tidak memiliki kapasitas untuk itu."},{"peribahasa":"dahulu elang pulau, kini telah menjadi burung pungguk","makna":"Peribahasa ini menggambarkan perubahan nasib yang drastis, dari posisi yang tinggi dan terhormat (elang) menjadi rendah dan tidak berdaya (pungguk). Ini merefleksikan kejatuhan seseorang dari kemuliaan ke kehinaan."},{"peribahasa":"rezeki elang tak akan dapat (dimakan) oleh musang (burung pipit)","makna":"Makna dari peribahasa ini adalah bahwa setiap makhluk telah ditentukan rezekinya masing-masing oleh Tuhan. Apa yang menjadi hak seseorang tidak akan bisa direbut atau diambil oleh orang lain, sebagaimana rezeki elang tidak akan bisa dimakan oleh musang."},{"peribahasa":"sepantun elang dengan ayam, lambat laun akan disambar jua","makna":"Ungkapan ini menggambarkan hubungan antara yang kuat dan yang lemah. Cepat atau lambat, pihak yang lebih kuat (elang) akan memangsa atau mengalahkan pihak yang lebih lemah (ayam), terutama jika keduanya terus-menerus berdekatan atau berinteraksi."},{"peribahasa":"sepantun elang dengan ayam, lambat laun disambar juga","makna":"Sama seperti peribahasa sebelumnya, ungkapan ini menggambarkan hubungan antara yang kuat dan yang lemah. Cepat atau lambat, pihak yang lebih kuat (elang) akan memangsa atau mengalahkan pihak yang lebih lemah (ayam), terutama jika keduanya terus-menerus berdekatan atau berinteraksi."},{"peribahasa":"seperti elang menyongsong angin","makna":"Peribahasa ini melambangkan kegagahan, keberanian, dan ketangguhan seseorang dalam menghadapi tantangan atau kesulitan. Orang tersebut tidak gentar melawan arus atau rintangan, layaknya elang yang terbang menentang arah angin dengan gagah berani."}]');
