insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('21973', 'em.pat', 'empat', '', '', '["Numeralia","Numeralia"]', '[{"nomor":"1","kelasKata":[{"kode":"num","nama":"Numeralia","tipe":"kelas_kata"}],"definisi":"bilangan yang dilambangkan dengan angka 4 (Arab) atau IV (Romawi)","contoh":[]},{"nomor":"2","kelasKata":[{"kode":"num","nama":"Numeralia","tipe":"kelas_kata"}],"definisi":"urutan ke-4 sesudah ke-3 dan sebelum ke-5","contoh":[{"nomor":2,"teks":"sekarang ia masih duduk di kelas --, mudah-mudahan tahun depan ia naik ke kelas lima"}]}]', null, '["berempat","berempat-empat","empat-empat","keempat","keempat-empatnya","memperempat","perempat","perempatan","seperempat"]', '["empat dimensi","empat kebenaran mulia","empat likur","empat mata","empat penjuru alam","empat persegi","empat persegi panjang","empat persegi serong","empat puluh hari","empat sehat lima sempurna","empat selipat","empat tepas dunia"]', '["empat susu, dua perut","masuk tiga, keluar empat","tentang mata dengan mata (antara empat mata)"]', '[]', '[{"peribahasa":"empat susu, dua perut","makna":"Peribahasa ini merujuk pada hubungan persaudaraan antara anak-anak yang lahir dari ayah yang sama namun dari ibu yang berbeda. Secara harfiah, ''empat susu'' menggambarkan dua ibu yang menyusui, sementara ''dua perut'' menunjuk pada dua rahim yang berbeda, namun mereka tetap terikat dalam satu garis keturunan ayah."},{"peribahasa":"masuk tiga, keluar empat","makna":"Ungkapan ini menggambarkan kondisi keuangan yang tidak seimbang, di mana pengeluaran lebih besar daripada pemasukan. Ini melambangkan pemborosan atau manajemen finansial yang buruk, yang pada akhirnya akan menyebabkan kerugian atau defisit."},{"peribahasa":"tentang mata dengan mata (antara empat mata)","makna":"Frasa ini digunakan untuk mendeskripsikan sebuah percakapan atau pertemuan yang bersifat sangat pribadi dan rahasia, yang hanya melibatkan dua orang saja. Tidak ada pihak ketiga yang mendengar atau menyaksikan interaksi tersebut, sehingga menjamin kerahasiaan penuh."}]');
