insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('22014', 'em.ping', 'emping', '', '', '["Nomina","Nomina","Nomina","Aceh"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"penganan yang dibuat dari padi yang belum masak benar atau dari biji-bijian (ditumbuk lalu disangrai)","contoh":[]},{"nomor":"2","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"penganan yang dibuat dari buah melinjo, biji-bijian, dan sebagainya ditumbuk, dibentuk bundar tipis-tipis, dikeringkan, dan digoreng seperti kerupuk","contoh":[]},{"nomor":"3","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"},{"kode":"Ach","nama":"Aceh","tipe":"bahasa"}],"definisi":"penganan khas Aceh yang terbuat dari beras gongseng yang dipipihkan, biasanya dikonsumsi dengan kelapa yang diparut dan taburan gula","contoh":[]}]', null, '["memperemping","mengemping","pengempingan"]', '["emping berdadih","emping ceplis","emping ketan","emping tike"]', '["emping berantah","emping terserak hari hujan","sudah biasa makan emping"]', '[]', '[{"peribahasa":"emping berantah","makna":"Peribahasa ini memiliki dua makna. Pertama, dapat merujuk pada seseorang yang tampaknya baik atau mulia, namun sebenarnya memiliki cacat atau kekurangan yang tersembunyi. Kedua, bisa juga berarti suatu pekerjaan atau hasil yang tidak sempurna dan masih tercampur dengan hal-hal yang tidak berguna, layaknya emping yang belum dibersihkan dari sekamnya."},{"peribahasa":"emping terserak hari hujan","makna":"Ungkapan ini melambangkan nasib sial atau kemalangan. Seseorang yang mengalami kejadian ini diibaratkan telah bersusah payah menyiapkan sesuatu yang berharga (emping), namun tidak dapat menikmatinya karena datangnya halangan yang tidak terduga (hujan). Ini adalah gambaran dari kesia-siaan dan kerugian."},{"peribahasa":"sudah biasa makan emping","makna":"Makna dari peribahasa ini adalah bahwa seseorang sudah memiliki banyak pengalaman hidup, baik suka maupun duka. Orang tersebut tidak mudah terkejut, tertipu, atau gentar menghadapi berbagai macam situasi karena telah terbiasa dengan asam garam kehidupan."}]');
