insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('22074', 'e.nak', 'enak', '', '', '["Adjektiva","Adjektiva","Adjektiva","Adjektiva","Cakapan"]', '[{"nomor":"1","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"}],"definisi":"sedap, lezat (tentang rasa)","contoh":[{"nomor":2,"teks":"kue ini -- rasanya"}]},{"nomor":"2","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"}],"definisi":"sehat atau segar (tentang kondisi badan)","contoh":[{"nomor":2,"teks":"pada hari ini kondisi badan saya kurang --"}]},{"nomor":"3","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"}],"definisi":"nikmat atau menyenangkan (tentang perasaan, suasana, dan sebagainya); nyaman","contoh":[{"nomor":2,"teks":"setelah mandi dengan air hangat, badan terasa --"}]},{"nomor":"4","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"},{"kode":"cak","nama":"Cakapan","tipe":"kelas_kata"}],"definisi":"pulas; lelap (tentang tidur)","contoh":[{"nomor":2,"teks":"pada malam itu, tidurnya -- sekali"}]}]', '{"text":"[Jawa Kuno inak ''kesejahteraan, damai, kemudahan, kesukaan, kepuasan, laku yang mudah; (m)enak: senang, bebas, puas; mudah, lancar, tidak terganggu; senang, ramah, menyenangkan, sesuai, lebih baik'']","languages":["Jawa Kuno"]}', '["berenak-enak","enak-enak","enakan","keenakan","memperenak","mengenakkan","seenak","seenaknya","terenak"]', '[]', '["enak lauk dikunyah-kunyah, enak kata diperkatakan","minyak habis sambal tak enak"]', '[]', '[{"peribahasa":"enak lauk dikunyah-kunyah, enak kata diperkatakan","makna":"Peribahasa ini menekankan pentingnya musyawarah dan pertimbangan yang matang. Sebagaimana lauk yang lezat perlu dinikmati dengan cara dikunyah perlahan, begitu pula perkataan atau nasihat yang baik perlu dibicarakan, didiskusikan, dan dipertimbangkan bersama agar menghasilkan keputusan terbaik."},{"peribahasa":"minyak habis sambal tak enak","makna":"Ungkapan ini menggambarkan suatu pekerjaan atau hubungan yang menjadi rusak atau tidak memuaskan pada akhirnya karena kehabisan sumber daya atau kesabaran. Ketika bekal atau modal utama telah habis, maka hasil akhir dari usaha tersebut tidak akan sempurna atau bahkan gagal total."}]');
