insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('22234', 'eng.gan', 'enggan', '', '', '["Adverbia"]', '[{"nomor":"1","kelasKata":[{"kode":"adv","nama":"Adverbia","tipe":"kelas_kata"}],"definisi":"tidak mau; tidak sudi; tidak suka","contoh":[{"nomor":2,"teks":"ia -- mengikuti nasihat pamannya"},{"nomor":4,"teks":"anak itu -- pergi ke sekolah"}]}]', null, '["berenggan-enggan","enggan-enggan","keengganan","mengenggankan","seenggan"]', '[]', '["alah mau, bertimbang enggan, cungkil merih akan pembayar","angguk enggan, geleng mau, unjuk tidak diberikan","bagai kerakap tumbuh di (di atas) batu, hidup enggan mati tak mau","enggan seribu daya, mau sepatah kata"]', '[]', '[{"peribahasa":"alah mau, bertimbang enggan, cungkil merih akan pembayar","makna":"Peribahasa ini menggambarkan sikap seseorang yang menginginkan sesuatu (alah mau), tetapi tidak mau menanggung risiko atau usaha yang diperlukan (bertimbang enggan). Pada akhirnya, ia terpaksa mengorbankan sesuatu yang sangat berharga (mencungkil merih) untuk memenuhi keinginannya itu, yang menunjukkan kurangnya perhitungan dan kebijaksanaan."},{"peribahasa":"angguk enggan, geleng mau, unjuk tidak diberikan","makna":"Ungkapan ini melukiskan sikap seseorang yang tidak tulus atau penuh kepura-puraan. Secara lahiriah, ia seolah-olah menolak (mengangguk enggan), padahal hatinya menginginkan (geleng mau). Namun, ketika diminta untuk menunjukkan bukti keseriusannya, ia tidak mau memberikannya. Ini adalah gambaran dari orang yang plin-plan dan tidak bisa dipegang kata-katanya."},{"peribahasa":"bagai kerakap tumbuh di (di atas) batu, hidup enggan mati tak mau","makna":"Peribahasa ini menggambarkan kondisi seseorang yang hidup dalam kemelaratan, penderitaan, dan kesengsaraan yang berkepanjangan. Ia tidak dapat menikmati kehidupan dengan layak, namun juga tidak kunjung menemui ajalnya. Ini adalah metafora untuk kehidupan yang serba sulit dan tanpa harapan."},{"peribahasa":"enggan seribu daya, mau sepatah kata","makna":"Makna dari peribahasa ini adalah bahwa jika seseorang tidak berniat atau tidak menyukai sesuatu, ia akan mencari seribu satu alasan untuk menolaknya. Sebaliknya, jika ia benar-benar menginginkannya, cukup dengan satu perkataan saja untuk menyatakan persetujuannya. Ini menyoroti kekuatan niat dan kemauan."}]');
insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('22246', 'enggang gading', 'enggang gading', '', 'enggang¹', '[]', '[{"nomor":"1","kelasKata":[],"definisi":"enggang berparuh besar yang berwarna kuning kemerahan dan terlihat seperti gading, tersebar di Semenanjung Malaya, Sumatra, dan Kalimantan〔Rhinoplax vigil〕","contoh":[]}]', null, '[]', '[]', '[]', '[]', '[]');
insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('22247', 'enggang papan', 'enggang papan', '', 'enggang¹', '[]', '[{"nomor":"1","kelasKata":[],"definisi":"enggang berleher putih kekuningan, berparuh dan bertanduk kuning, pipih, dan datar, tersebar di India dan Asia tenggara (Indonesia hanya di Sumatra)〔Buceros bicornis〕","contoh":[]}]', null, '[]', '[]', '[]', '[]', '[]');
insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('22240', 'eng.gang', 'enggang', '', '', '["Nomina"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"burung arboreal berukuran besar, berwarna hitam atau cokelat dan putih, berparuh panjang dan besar, bertanduk menonjol di atas paruh, betina mengerami telur di dalam rongga pohon yang ditutup lumpur kecuali sedikit celah untuk makan dari jantan, pemakan buah dan serangga, tersebar di Afrika dan Asia tropis; rangkok; rangkong〔Bucerotidae〕","contoh":[]}]', null, '[]', '["enggang cula","enggang emas","enggang gading","enggang jambul","enggang khilingan","enggang klihingan","enggang papan"]', '["dengar cakap enggang, makan buah beluluk, dengar cakap orang, terjun masuk lubuk","mabuk di enggang lalu","makanan enggang akan dimakan pipit","mara hinggap mara terbang, enggang lalu ranting patah","mendengarkan cakap enggang","pipit meminang anak enggang","selama enggang mengeram","yang enggang sama enggang juga, yang pipit sama pipit juga","yang pipit sama pipit, yang enggang sama enggang"]', '["selama enggang mengeram"]', '[{"peribahasa":"dengar cakap enggang, makan buah beluluk, dengar cakap orang, terjun masuk lubuk","makna":"Peribahasa ini memberikan nasihat untuk tidak mudah percaya pada perkataan orang lain tanpa pertimbangan. Mengikuti omongan yang indah namun menyesatkan (cakap enggang) dapat berakibat fatal, sama seperti terjun ke lubuk yang dalam. Sebaliknya, lebih baik menerima sesuatu yang nyata meskipun sederhana (buah beluluk)."},{"peribahasa":"mabuk di enggang lalu","makna":"Ungkapan ini menggambarkan seseorang yang jatuh cinta atau tergila-gila pada orang yang jauh lebih tinggi kedudukannya, status sosialnya, atau kekayaannya. Rasa cinta tersebut dianggap tidak realistis dan hanya akan membawa kekecewaan, karena perbedaan yang terlalu besar."},{"peribahasa":"makanan enggang akan dimakan pipit","makna":"Peribahasa ini melukiskan seseorang yang memiliki keinginan atau ambisi yang jauh melampaui kemampuannya. Ia mencoba melakukan sesuatu yang biasanya hanya bisa dilakukan oleh orang yang lebih hebat atau berkuasa, sehingga usahanya kemungkinan besar akan sia-sia."},{"peribahasa":"mara hinggap mara terbang, enggang lalu ranting patah","makna":"Makna dari peribahasa ini adalah bahwa suatu peristiwa atau tuduhan sering kali dikaitkan dengan orang yang kebetulan berada di tempat kejadian, meskipun ia tidak bersalah. Ini menggambarkan bagaimana seseorang bisa menjadi korban keadaan atau kambing hitam hanya karena kehadiran sesaat."},{"peribahasa":"mendengarkan cakap enggang","makna":"Ungkapan ini berarti mendengarkan atau mempercayai perkataan yang indah, muluk, tetapi tidak berisi atau tidak dapat dipertanggungjawabkan. Ini adalah peringatan agar tidak mudah terbuai oleh janji-janji manis yang tidak realistis."},{"peribahasa":"pipit meminang anak enggang","makna":"Peribahasa ini menggambarkan situasi di mana seseorang dari kalangan bawah atau tidak sepadan (pipit) mencoba menjalin hubungan atau bersaing dengan orang dari kalangan yang jauh lebih tinggi (enggang). Tindakan ini dianggap tidak pantas dan kemungkinan besar akan berakhir dengan kegagalan atau penolakan."},{"peribahasa":"selama enggang mengeram","makna":"Ungkapan ini digunakan untuk menyatakan suatu jangka waktu yang sangat lama dan tidak pasti kapan akan berakhir. Proses pengeraman enggang yang memakan waktu lama dijadikan metafora untuk penantian yang panjang dan melelahkan."},{"peribahasa":"yang enggang sama enggang juga, yang pipit sama pipit juga","makna":"Peribahasa ini menekankan pentingnya mencari pasangan, teman, atau lingkungan yang setara atau sepadan. Hubungan akan lebih harmonis dan langgeng jika terjalin antara orang-orang yang memiliki latar belakang, status, dan pemikiran yang selevel."},{"peribahasa":"yang pipit sama pipit, yang enggang sama enggang","makna":"Sama seperti peribahasa sebelumnya, ungkapan ini menegaskan prinsip kesetaraan dalam pergaulan. Seseorang secara alami akan lebih cocok dan nyaman bergaul dengan orang-orang yang berada dalam lingkaran sosial atau tingkat yang sama dengannya."}]');
