insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('22266', 'eng.kau', 'engkau', '', '', '["Pronomina"]', '[{"nomor":"1","kelasKata":[{"kode":"pron","nama":"Pronomina","tipe":"kelas_kata"}],"definisi":"yang diajak bicara, yang disapa (dipakai untuk orang yang sama atau lebih rendah kedudukannya), digunakan juga untuk berdoa kepada Tuhan (Engkau)","contoh":[]}]', null, '["berengkau"]', '[]', '["aku alah engkau tak menang","gereklah langit olehmu, engkau takkan kusaraki juga"]', '[]', '[{"peribahasa":"aku alah engkau tak menang","makna":"Peribahasa ini menggambarkan suatu perselisihan atau konflik di mana tidak ada pihak yang benar-benar keluar sebagai pemenang. Meskipun satu pihak mungkin kalah atau mengalah, pihak lainnya juga tidak memperoleh kemenangan yang memuaskan karena keduanya sama-sama menderita kerugian atau menanggung akibat buruk dari pertikaian tersebut."},{"peribahasa":"gereklah langit olehmu, engkau takkan kusaraki juga","makna":"Ungkapan ini melambangkan keteguhan pendirian atau kebencian yang mendalam. Maknanya adalah, sekeras apa pun usaha atau ancaman yang dilakukan oleh seseorang, bahkan jika ia mampu mengguncang langit sekalipun, pendirian atau keputusan pihak yang lain tidak akan pernah goyah atau berubah."}]');
