insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('22517', 'e.rat', 'erat', '', '', '["Adjektiva","Adjektiva","Adjektiva"]', '[{"nomor":"1","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"}],"definisi":"kuat sehingga tidak mudah lepas (tentang ikatan, pegangan)","contoh":[{"nomor":2,"teks":"pegangannya -- sekali sehingga sukar dilepaskan"}]},{"nomor":"2","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"}],"definisi":"teguh (tentang janji, pertalian)","contoh":[{"nomor":2,"teks":"telah diadakan perjanjian yang -- antara kedua negara itu"}]},{"nomor":"3","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"}],"definisi":"karib benar (tentang persahabatan)","contoh":[{"nomor":2,"teks":"kedua perantau itu telah menjalin persahabatan yang --"}]}]', null, '["erat-erat","keeratan","mempererat","mengeratkan"]', '[]', '["hujan tak sekali jatuh, simpai tak sekali erat","mengebat erat-erat, membuhul mati-mati","menggenggam erat, membuhul mati"]', '[]', '[{"peribahasa":"hujan tak sekali jatuh, simpai tak sekali erat","makna":"Peribahasa ini mengajarkan bahwa segala sesuatu yang baik dan kokoh tidak dapat dicapai secara instan. Hubungan yang kuat, persahabatan yang erat, atau keberhasilan yang langgeng membutuhkan proses, waktu, dan usaha yang berkelanjutan, bukan hanya sekali jadi."},{"peribahasa":"mengebat erat-erat, membuhul mati-mati","makna":"Ungkapan ini menekankan pentingnya keteguhan dan komitmen yang kuat dalam memegang janji, prinsip, atau kesepakatan. Segala sesuatu yang telah diikat atau disepakati harus dipegang teguh dan tidak boleh dilanggar, menunjukkan integritas dan konsistensi."},{"peribahasa":"menggenggam erat, membuhul mati","makna":"Sama seperti peribahasa sebelumnya, ungkapan ini melambangkan kesungguhan dan keteguhan dalam memegang sesuatu, baik itu janji, rahasia, maupun prinsip. Sesuatu yang telah digenggam erat dan diikat mati tidak akan dilepaskan atau dibocorkan, menunjukkan loyalitas dan kepercayaan."}]');
